{
    "core_hypothesis_preview": "Aerosol liquid water acts as a hygroscopic and acidic medium that accelerates heterogeneous uptake and aqueous‑phase oxidation of gaseous precursors, thereby driving the rapid, explosive growth of secondary organic and inorganic aerosols during severe winter haze.",
    "subtopics": [
        {
            "topic_name": "Field observations of ALW properties and aerosol composition",
            "description": "Characterizes measured aerosol liquid water content, pH, viscosity, and the associated organic/inorganic aerosol fractions during severe winter haze episodes in North China.",
            "sub_questions": [
                "What are the typical ranges of aerosol liquid water content, pH, and viscosity observed during severe winter haze events?",
                "How do these ALW properties correlate with measured concentrations of secondary inorganic (sulfate, nitrate) and organic aerosol components?",
                "Can field measurements directly link variations in ALW acidity or water activity to rapid increases in SOA/SIA mass during haze episodes?"
            ],
            "assigned_plan_ids": ["plan_0_0", "plan_4_9", "plan_4_8", "plan_4_7"],
            "keywords": ["aerosol liquid water", "pH", "viscosity", "winter haze", "secondary aerosol"]
        },
        {
            "topic_name": "Modeling gaps and need for explicit ALW coupling",
            "description": "Examines how current chemical transport and aerosol models omit or simplify ALW‑mediated heterogeneous chemistry, and the consequences for predicting SOA/SIA growth.",
            "sub_questions": [
                "Which major aerosol–chemistry models currently lack explicit representation of ALW‑mediated heterogeneous reactions?",
                "How does the absence of ALW coupling affect simulated growth rates of SOA and SIA in winter haze scenarios?",
                "What specific model upgrades (e.g., aqueous uptake, pH‑dependent kinetics) are proposed to improve predictions of explosive aerosol growth?"
            ],
            "assigned_plan_ids": ["plan_0_0", "plan_1_3", "plan_1_2", "plan_2_4", "plan_2_5", "plan_2_6"],
            "keywords": ["model coupling", "CTM", "MACC", "GEOS‑Chem", "ALW processes"]
        },
        {
            "topic_name": "Aqueous‑phase chemical mechanisms driving SOA/SIA",
            "description": "Focuses on the key aqueous reactions—SO₂ dissolution, dicarbonyl uptake, IVOC oxidation, HOM formation—and how ALW acidity and water activity control their rates.",
            "sub_questions": [
                "What are the primary aqueous‑phase reactions (e.g., SO₂ dissolution, dicarbonyl uptake) that enhance secondary aerosol formation under high humidity?",
                "How do ALW acidity and water activity modulate heterogeneous oxidation pathways of IVOCs and the formation of highly oxygenated molecules (HOMs)?",
                "What kinetic data exist for the uptake coefficients of SO₂, H₂SO₄, and organic acids into aerosol liquid water under haze‑relevant conditions?"
            ],
            "assigned_plan_ids": ["plan_1_3", "plan_2_5", "plan_2_6", "plan_5_10", "plan_4_7"],
            "keywords": ["aqueous chemistry", "SO₂ uptake", "dicarbonyl", "IVOC", "HOM", "acidity"]
        },
        {
            "topic_name": "Emission inventories and precursor measurements for ALW‑driven pathways",
            "description": "Identifies gaps in current emissions inventories for key precursors (IVOCs, monoterpenes, etc.) and outlines needed observations to quantify their contribution to ALW‑mediated aerosol growth.",
            "sub_questions": [
                "Which precursor species (e.g., IVOCs, monoterpenes) are currently under‑represented in emission inventories for winter haze?",
                "How would improved quantification of these precursors affect assessments of ALW‑mediated secondary organic and inorganic aerosol formation?",
                "What targeted field campaigns or laboratory studies are recommended to capture ALW‑relevant precursor emissions?"
            ],
            "assigned_plan_ids": ["plan_0_0", "plan_2_4", "plan_5_10"],
            "keywords": ["emission inventory", "IVOC", "monoterpene", "precursor measurement", "winter haze"]
        }
    ]
}
